55	    it.todo("should keep intermediate amounts as fractions and round only the final premium");
56	  });
57	
58	  describe("claim - basic single-item reimbursement", () => {
59	    it.todo("should pay 400 G for standard steel sword enchantment 3 with 500 G damage (full minus 100 deductible)");
60	    it.todo("should pay 100 G for a rune with 200 G damage (full minus 100 deductible)");
61	    it.todo("should report remaining cap after a basic claim (sword cap 2000, claim 500 → remaining 1600)");
62	  });
63	
64	  describe("claim - high enchantment clause", () => {
